import React, { useEffect, useState } from "react";
import Navbar from "../Pages/Navbar";
import {
  Box,
  Button,
  Flex,
  Heading,
  Input,
  Spinner,
  Text,
  useToast,
  FormControl,
  FormLabel,
} from "@chakra-ui/react";
import { useDispatch, useSelector } from "react-redux";
import { loginFetch } from "../Redux/UserReducer/action";
import { Link, useNavigate } from "react-router-dom";
import { showToast } from "./SignUp";

const Login = () => {
  const [form, setForm] = useState({ email: "", password: "" });

  const userStore = useSelector((store) => store.UserReducer);
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const toast = useToast();

  const handleInput = (e) => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: value });
  };

  const handleLogin = () => {
    dispatch(loginFetch(form)).then(() => {
      const user = JSON.parse(localStorage.getItem("user"));

      if (user?.message) {
        showToast({ toast, message: "Login successful", color: "green" });
        setForm({ email: "", password: "" });
      } else {
        showToast({ toast, message: userStore?.isError, color: "red" });
      }
    });
  };

  useEffect(() => {
    if (userStore.isAuth) {
      if (userStore.role === "user") {
        navigate("/home");
      } else if (userStore.role === "admin") {
        navigate("/admin/dashboard");
      } else if (userStore.role === "teacher") {
        navigate("/TeacherDashboard");
      }
    }
  }, [userStore?.isAuth, userStore?.role]);

  return (
    <Box bg="#f7f9fa" minH="100vh">
      <Navbar />

      <Flex justify="center" align="center" py={10}>
        <Box
          bg="white"
          p={8}
          borderRadius="lg"
          boxShadow="lg"
          w={{ base: "90%", md: "400px" }}
        >
          <Heading size="md" mb={6}>
            Log in to your account
          </Heading>

          {/* Email */}
          <FormControl mb={4}>
            <FormLabel>Email</FormLabel>
            <Input
              name="email"
              value={form.email}
              onChange={handleInput}
              border="1px solid #d1d7dc"
              _focus={{
                borderColor: "#A435F0",
                boxShadow: "0 0 0 1px #A435F0",
              }}
            />
          </FormControl>

          {/* Password */}
          <FormControl mb={6}>
            <FormLabel>Password</FormLabel>
            <Input
              type="password"
              name="password"
              value={form.password}
              onChange={handleInput}
              border="1px solid #d1d7dc"
              _focus={{
                borderColor: "#A435F0",
                boxShadow: "0 0 0 1px #A435F0",
              }}
            />
          </FormControl>

          {/* Button */}
          <Button
            w="100%"
            bg="#A435F0"
            color="white"
            _hover={{ bg: "#8710d8" }}
            onClick={handleLogin}
          >
            {userStore.loading ? <Spinner /> : "Log in"}
          </Button>

          {/* Signup */}
          <Text mt={4} fontSize="sm">
            Don’t have an account?{" "}
            <Link to="/signup">
              <Text as="span" color="#A435F0" fontWeight="600">
                Sign up
              </Text>
            </Link>
          </Text>
        </Box>
      </Flex>
    </Box>
  );
};

export default Login;
